parameters.jsCode:
// Extraer JSON del output del agente IA
const raw = $input.item.json.output || '';

// Intentar extraer JSON de distintos formatos
let parsed;
try {
  // Caso 1: JSON dentro de bloques ```json
  const match1 = raw.match(/```json\s*([\s\S]*?)\s*```/);
  if (match1) { 
    parsed = JSON.parse(match1[1]); 
  } else {
    // Caso 2: Buscar cualquier cosa entre { } o [ ] (ahora con soporte para listas)
    const match2 = raw.match(/([\{\[][\s\S]*[\}\]])/);
    if (match2) { 
      parsed = JSON.parse(match2[1]); 
    } else { 
      parsed = JSON.parse(raw); 
    }
  }

  // Si la IA mandó una lista [ ... ], tomamos solo el primer elemento
  if (Array.isArray(parsed)) {
    parsed = parsed[0];
  }
} catch (e) {
  // Si falla, el error aparecerá en n8n
  parsed = { intent: 'informacion_incompleta', missing_fields: ['parse_error'], error_msg: e.message };
}

// Preservar contexto de sesión (Jala estos datos de tus nodos)
parsed._numeroremitente = $('Webhook_Unificado').item.json.body.data.key.remoteJid;
parsed._nombrecontacto  = $('organizar_datos').item.json.nombrecontacto;
parsed._instancia       = $('Webhook_Unificado').item.json.body.instance;
// Normalizar intent_type a intent para no romper los nodos siguientes
parsed.intent = parsed.intent_type || parsed.intent;

return [{ json: parsed }];

// Obtener el JSON crudo del Agente
const agente = $('parsear_json_agente').item.json;

// Si la IA usó memory y mandó correcciones en lugar del objeto principal, las extraemos
const datosFinancieros = agente.corrections ? agente.corrections : agente;

// Extraer URL del ticket si existe
const urlTicket = $input.item.json.url_ticket || $input.item.json.agente_data?.url_ticket || '';

const timestamp = new Date().getTime();
const idMovimiento = `MOV-${timestamp}`;

return [{
  json: {
    id_movimiento:           idMovimiento,
    fecha:                   datosFinancieros.fecha || new Date().toISOString().split('T')[0],
    tipo:                    datosFinancieros.tipo || '',
    categoria:               datosFinancieros.categoria || '',
    concepto:                datosFinancieros.concepto || datosFinancieros.descripcion || '',
    monto:                   datosFinancieros.monto || 0,
    moneda:                  datosFinancieros.moneda || 'MXN',
    url_ticket:              urlTicket,
    nivel_confiabilidad:     Math.round((agente.confidence_score || agente.confidence_level || 0) * 100),
    estado:                  'pendiente',
    observacion_ia:          [
      agente.proveedor ? `Proveedor: ${agente.proveedor}` : '',
      agente.origen    ? `Origen: ${agente.origen}` : '',
      agente.metodo_pago ? `Método de pago: ${agente.metodo_pago}` : '',
      agente.duplicate_probability > 0.5 ? `⚠️ Posible duplicado (${Math.round(agente.duplicate_probability * 100)}%)` : ''
    ].filter(Boolean).join(' | '),
    confirmado_por:          '',
    fecha_confirmacion:      '',
    // Contexto de sesión preservado por si acaso
    _numeroremitente:        agente._numeroremitente,
    _nombrecontacto:         agente._nombrecontacto,
    _instancia:              agente._instancia
  }
}];

// ====== PARSEADOR V8 (El Sabueso Definitivo) ======

const rawData = $('Webhook_Unificado').first().json || $json;
let texto = '';

// 🐕 Soltamos al Sabueso para encontrar en qué bolsillo está el voto
function buscarVotoEscondido(obj) {
    if (!obj || typeof obj !== 'object') return null;
    if (Array.isArray(obj)) {
        for (let item of obj) {
            let hallazgo = buscarVotoEscondido(item);
            if (hallazgo) return hallazgo;
        }
    } else {
        // En WhatsApp Nuevo (Detecta dónde diste click)
        if (obj.voters && Array.isArray(obj.voters) && obj.voters.length > 0 && typeof obj.name === 'string') {
            return obj.name; 
        }
        // En WhatsApp Viejo
        if (obj.selectedOptions && Array.isArray(obj.selectedOptions) && obj.selectedOptions.length > 0) {
            return obj.selectedOptions[0];
        }
        for (let key in obj) {
            let hallazgo = buscarVotoEscondido(obj[key]);
            if (hallazgo) return hallazgo;
        }
    }
    return null;
}

texto = buscarVotoEscondido(rawData) || "";

// Si la encuesta falla, bajamos al texto normal
if (!texto) {
    texto = rawData.body?.data?.message?.conversation || 
            rawData.body?.data?.message?.buttonsResponseMessage?.selectedDisplayText || "";
}

texto = texto.trim().toUpperCase();

// ✂️ MÁGIA: Extraer separar Acción (SI) y Folio (MOV)
const match = texto.match(/^(SI|SÍ|NO|CONFIRMAR|RECHAZAR)\s+(MOV-\d+)/i);

if (!match) {
  return [{ json: { parse_ok: false, accion: null, id_movimiento: null, fallo_texto: texto } }];
}

const accionRaw = match[1].toUpperCase();
let accion = 'NO';
if (accionRaw === 'SÍ' || accionRaw === 'SI' || accionRaw === 'CONFIRMAR') {
    accion = 'SI';
}

return [{
  json: {
    parse_ok: true,
    accion: accion,
    id_movimiento: match[2].toUpperCase(),
    instancia: rawData.instance || "",
    numeroremitente: rawData.body?.data?.key?.remoteJid || "",
    nombrecontacto: rawData.body?.data?.pushName || ""
  }
}];

